from itertools import combinations

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    a_set = set(a)

    # BFS/DFS: try sets of b values
    # Start with {0}, try to cover all a_i
    from functools import lru_cache

    def covered(b):
        diffs = set()
        for x in b:
            for y in b:
                diffs.add(x - y)
        return a_set <= diffs

    def search(b, depth):
        if covered(b):
            return True
        if depth == 0:
            return False
        b_list = list(b)
        candidates = set()
        for x in b_list:
            for ai in a:
                candidates.add(x + ai)
                candidates.add(x - ai)
        for c in candidates:
            if search(b | {c}, depth - 1):
                return True
        return False

    print("YES" if search(frozenset([0]), n - 1) else "NO")

t = int(input())
for _ in range(t):
    solve()

